import dayjs, { extend } from 'dayjs';
import utc from 'dayjs/plugin/utc';
import ky, { type KyRequest, type KyResponse } from 'ky';

import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getFibonacciNumber } from '@utils/getFibonacciNumber';
import { wait } from '@utils/wait';

import { logger } from '@utils/logger';

const limitInSeconds = 60 * 60;

const getTimingWithLimit = (timingInSec: number, limitInSec: number) => {
  if (timingInSec > limitInSec) {
    return limitInSec;
  }
  return timingInSec;
};

extend(utc);

export const configsClient = ky.extend({
  timeout: 60000,
  retry: {
    limit: 2,
    methods: ['get', 'post'],
  },
  hooks: {
    beforeRequest: [
      async (request) => {
        const { configsBaseUrl } = await getLocalStorageData(
          LocalStorageKey.ConfigsBaseUrl,
        );

        let url = request.url;

        if (url.startsWith(process.env.CONFIG_BASE_URL_1) && configsBaseUrl) {
          url = url.replace(process.env.CONFIG_BASE_URL_1, configsBaseUrl);
        }

        logger.info(
          'configsClient: beforeRequest: request',
          JSON.stringify({
            body: request.body,
            url: request.url,
            method: request.method,
            headers: request.headers,
          }),
        );

        const headers = new Headers(request.headers);
        headers.set('Cache-Control', 'no-cache, no-store, must-revalidate');
        headers.set('Pragma', 'no-cache');
        headers.set('Expires', '0');

        return new Request(url, {
          ...request,
          headers,
        });
      },
    ],
    beforeRetry: [
      async ({ retryCount, request }) => {
        const { configsBaseUrl } = await getLocalStorageData(
          LocalStorageKey.ConfigsBaseUrl,
        );
        if (
          !configsBaseUrl ||
          configsBaseUrl === process.env.CONFIG_BASE_URL_1
        ) {
          await setLocalStorageData({
            [LocalStorageKey.ConfigsBaseUrl]: process.env.CONFIG_BASE_URL_2,
          });
        }
        logger.info(
          'configsClient: beforeRetry: request',
          JSON.stringify({
            body: request.body,
            url: request.url,
            method: request.method,
            headers: request.headers,
          }),
        );
        logger.info('configsClient: beforeRetry: retryCount', retryCount);

        await wait(
          getTimingWithLimit(getFibonacciNumber(retryCount), limitInSeconds) *
            1000,
        );
        return;
      },
    ],
    afterResponse: [
      async (request, options, response) => {
        if (response.ok) {
          const responseClone = response.clone() as KyResponse;
          const timestampUtc = dayjs.utc().format();

          let responseData = null;
          try {
            responseData = await responseClone.json();
          } catch (err) {
            responseData = null;
          }

          const requestLog = {
            timestampUtc,
            status: response.status,
            statusText: response.statusText,
            url: request.url,
          };
          let { apiHttpSuccess } = await getLocalStorageData(
            LocalStorageKey.ApiHttpSuccess,
          );
          if (!apiHttpSuccess) {
            apiHttpSuccess = {};
          }
          await setLocalStorageData({
            apiHttpSuccess: {
              ...apiHttpSuccess,
              [request.url]: requestLog,
            },
          });
        }

        logger.info(
          'configsClient: afterResponse: response',
          JSON.stringify(
            {
              status: response.status,
              statusText: response.statusText,
              url: request.url,
            },
            null,
            2,
          ),
        );
        return response;
      },
    ],
    beforeError: [
      async (error) => {
        const { request, response, message } = error;
        const responseClone = response.clone() as KyResponse;
        const requestClone = request.clone() as KyRequest;

        let requestData = null;
        let errorData = null;
        try {
          requestData = await requestClone.json();
          errorData = await responseClone.json();
        } catch {
          requestData = null;
          errorData = null;
        }
        const timestampUtc = dayjs.utc().format();
        const errorLog = {
          timestampUtc,
          message,
          errorData,
          status: responseClone.status,
          statusText: responseClone.statusText,
          requestData,
        };
        let { apiHttpErrors } = await getLocalStorageData(
          LocalStorageKey.ApiHttpErrors,
        );
        if (!apiHttpErrors) {
          apiHttpErrors = {};
        }
        await setLocalStorageData({
          apiHttpErrors: {
            ...apiHttpErrors,
            [responseClone.url]: errorLog,
          },
        });

        logger.info(
          'configsClient: beforeError: error',
          JSON.stringify(error, null, 2),
        );
        return error;
      },
    ],
  },
});
